	private static IrNodeId pushFilterToSmallestAssuredInput(PlanIr source, PlanIrBuilder builder,
			IrNodeId sourceId, ScalarExpr condition, BindingMask conditionVars) {
		IrNode node = source.node(sourceId);
		if (!node.bindings().assured().containsAll(conditionVars)) {
			return null;
		}
		if (node.op() == IrOp.JOIN && node.inputs().size() == 2 && node.semantics().barrierFree()) {
			if (isConnectedFinitePrefix(source, node, conditionVars)) {
				return builder.filter(builder.copySubtreeFrom(source, sourceId), condition);
			}
			IrNode left = source.node(node.inputs().get(0));
			IrNode right = source.node(node.inputs().get(1));
			boolean leftFinite = containsFiniteRelation(source, node.inputs().get(0));
			boolean rightFinite = containsFiniteRelation(source, node.inputs().get(1));
			if (rightFinite && !leftFinite && right.bindings().assured().containsAll(conditionVars)) {
				IrNodeId pushedRight = pushFilterToSmallestAssuredInput(source, builder, node.inputs().get(1),
						condition, conditionVars);
				if (pushedRight != null) {
					return builder.join(builder.copySubtreeFrom(source, node.inputs().get(0)), pushedRight);
				}
			}
			if (left.bindings().assured().containsAll(conditionVars)) {
				IrNodeId pushedLeft = pushFilterToSmallestAssuredInput(source, builder, node.inputs().get(0),
						condition, conditionVars);
				if (pushedLeft != null) {
					return builder.join(pushedLeft, builder.copySubtreeFrom(source, node.inputs().get(1)));
				}
			}
			if (right.bindings().assured().containsAll(conditionVars)) {
				IrNodeId pushedRight = pushFilterToSmallestAssuredInput(source, builder, node.inputs().get(1),
						condition, conditionVars);
				if (pushedRight != null) {
					return builder.join(builder.copySubtreeFrom(source, node.inputs().get(0)), pushedRight);
				}
			}
		}
		if (node.op() == IrOp.FILTER && node.inputs().size() == 1 && node.semantics().barrierFree()
				&& node.attr()instanceof IrAttr.Condition existingCondition) {
			IrNodeId pushedInput = pushFilterToSmallestAssuredInput(source, builder, node.inputs().get(0),
					condition, conditionVars);
			if (pushedInput != null) {
				return builder.filter(pushedInput, existingCondition.expression());
			}
		}
		return builder.filter(builder.copySubtreeFrom(source, sourceId), condition);
	}

	private static boolean isConnectedFinitePrefix(PlanIr source, IrNode node, BindingMask conditionVars) {
		if (node.op() != IrOp.JOIN || node.inputs().size() != 2) {
			return false;
		}
		IrNode left = source.node(node.inputs().get(0));
		IrNode right = source.node(node.inputs().get(1));
		boolean leftAssures = left.bindings().assured().containsAll(conditionVars);
		boolean rightAssures = right.bindings().assured().containsAll(conditionVars);
		if (leftAssures == rightAssures) {
			return false;
		}
		IrNodeId finiteSide = leftAssures ? node.inputs().get(1) : node.inputs().get(0);
		IrNodeId assuringSide = leftAssures ? node.inputs().get(0) : node.inputs().get(1);
		return containsFiniteRelation(source, finiteSide)
				&& source.node(finiteSide)
						.bindings()
						.possible()
						.intersects(source.node(assuringSide).bindings().possible());
	}

	private static boolean containsFiniteRelation(PlanIr source, IrNodeId sourceId) {
		IrNode node = source.node(sourceId);
		if (node.op() == IrOp.BINDING_SET_ASSIGNMENT) {
			return true;
		}
		for (IrNodeId input : node.inputs()) {
			if (containsFiniteRelation(source, input)) {
				return true;
			}
		}
		return false;
	}

	private static IrNodeId valuesAnchor(PlanIrBuilder builder, BindingSymbol variable, List<Value> values) {
		if (variable == null || values == null || values.isEmpty()) {
			throw new IllegalStateException("Scalar capture is not a finite VALUES anchor");
		}
		List<FiniteRelation.Row> rows = new ArrayList<>(values.size());
		for (Value value : values) {
			rows.add(new FiniteRelation.Row(List.of(FiniteRelation.Cell.bound(value))));
		}
		return builder.values(new FiniteRelation(List.of(variable), rows));
	}

	private static IrAttr.ProjectionAttr identityProjection(RuleCapture capture, BindingMask mask, boolean subquery) {
		Set<String> names = new LinkedHashSet<>(capture.ir().universe().names(mask));
		List<IrAttr.ProjectionBinding> bindings = new ArrayList<>(names.size());
		for (String name : names) {
			BindingSymbol symbol = capture.ir().universe().symbol(name);
			bindings.add(new IrAttr.ProjectionBinding(symbol, symbol));
		}
		return new IrAttr.ProjectionAttr(bindings, subquery);
	}

	private static BindingMask projectionTargetMask(RuleCapture capture, String projectionCaptureName) {
		IrNode projection = capture.node(projectionCaptureName);
		if (!(projection.attr()instanceof IrAttr.ProjectionAttr attr)) {
			return BindingMask.EMPTY;
		}
		List<BindingSymbol> targets = attr.bindings().stream().map(IrAttr.ProjectionBinding::target).toList();
		return org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.ir.BindingShape
				.maskOfSymbols(capture.ir().universe(), targets);
	}

	private static IrNodeId copyWithRootSemantics(PlanIr source, IrNodeId sourceId, PlanIrBuilder builder,
			SemanticProps rootSemantics) {
		return copyWithRootSemantics(source, sourceId, builder, rootSemantics, new java.util.HashMap<>());
	}

	private static IrNodeId copyWithRootSemantics(PlanIr source, IrNodeId sourceId, PlanIrBuilder builder,
			SemanticProps rootSemantics, Map<IrNodeId, IrNodeId> remap) {
		IrNodeId existing = remap.get(sourceId);
		if (existing != null) {
			return existing;
		}
		IrNode sourceNode = source.node(sourceId);
		List<IrNodeId> copiedInputs = new ArrayList<>(sourceNode.inputs().size());
		for (IrNodeId input : sourceNode.inputs()) {
			copiedInputs.add(builder.copySubtreeFrom(source, input, remap));
		}
		IrNodeId copied = builder.add(sourceNode.op(), copiedInputs, sourceNode.attr(), rootSemantics,
				sourceNode.physical(), sourceNode.proofs());
		remap.put(sourceId, copied);
		return copied;
	}

